#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        while (Q--) {
            int L, R, K;
            scanf("%d %d %d", &L, &R, &K);
            int count = 0;
            for (int i = L - 1; i < R; i++) {
                int freq = 0;
                for (int j = 0; j < N; j++) {
                    if (A[j] == A[i]) {
                        freq++;
                    }
                }
                if (freq <= K) {
                    count++;
                }
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

