let idx = 0;

function nextLine() {
    return input[idx++];
}

function nextInt() {
    return parseInt(nextLine());
}

function nextInts() {
    return nextLine().split(' ').map(x => parseInt(x));
}

let T = nextInt();
while (T-- > 0) {
    let [N, Q] = nextInts();
    let A = nextInts();
    while (Q-- > 0) {
        let [L, R, K] = nextInts();
        let count = 0;
